import Tile from"./Tile.js";import TileState from"./TileState.js";const DEFAULT_EXTENT=[0,0,4096,4096];class VectorTile extends Tile{constructor(t,e,s,i,r,o){super(t,e,o),this.consumers=0,this.extent_=null,this.format_=i,this.features_=null,this.loader_,this.projection_=null,this.tileLoadFunction_=r,this.url_=s}disposeInternal(){this.setState(TileState.ABORT),super.disposeInternal()}getExtent(){return this.extent_||DEFAULT_EXTENT}getFormat(){return this.format_}getFeatures(){return this.features_}getKey(){return this.url_}getProjection(){return this.projection_}load(){this.state==TileState.IDLE&&(this.setState(TileState.LOADING),this.tileLoadFunction_(this,this.url_),this.loader_(null,NaN,null))}onLoad(t,e,s){this.setProjection(e),this.setFeatures(t),this.setExtent(s)}onError(){this.setState(TileState.ERROR)}setExtent(t){this.extent_=t}setFeatures(t){this.features_=t,this.setState(TileState.LOADED)}setProjection(t){this.projection_=t}setLoader(t){this.loader_=t}}export default VectorTile;